def token_case(s):
    exceptions = ['URL', 'ID']
    tokens = s.split('_')
    result = []
    for i, t in enumerate(tokens):
        if t.upper() in exceptions:
            result.append(t)
        else:
            if i == 0:
                result.append(t.lower())
            else:
                result.append(t.capitalize())
    return ''.join(result)
